import { environment, RuntimeExtensions } from "@zuplo/runtime";

export async function runtimeInit(runtime: RuntimeExtensions) {
  runtime.notFoundHandler = async (request) => {
    const requestedPath = new URL(request.url).pathname;

    return new Response(
      JSON.stringify({
        error: "Not Found",
        path: requestedPath,
        run_id: environment.ZEALT_RUN_ID,
      }),
      {
        status: 404,
        headers: {
          "Content-Type": "application/json",
          "X-Custom-404": "true",
        },
      }
    );
  };
}

